import React, { useEffect, useMemo, useState } from 'react';
import { useAuth } from '../auth/AuthContext';
import { apiRequest } from '../api/client';

const requestStatusOptions = ['ALL', 'OPEN', 'MATCHED', 'IN_PROGRESS', 'FULFILLED', 'CANCELLED', 'EXPIRED'];
const roleOptions = ['ALL', 'ADMIN', 'DONOR', 'RECIPIENT'];

function byCreatedDesc(a, b) {
  return new Date(b.created_at || 0).getTime() - new Date(a.created_at || 0).getTime();
}

function formatDate(value) {
  if (!value) return '-';
  return new Date(value).toLocaleString();
}

function AdminPage({ view = 'recipient-requests' }) {
  const { token, setFlash } = useAuth();

  const [loading, setLoading] = useState(false);
  const [analytics, setAnalytics] = useState(null);
  const [requests, setRequests] = useState([]);
  const [donorRequests, setDonorRequests] = useState([]);
  const [requestStatus, setRequestStatus] = useState('ALL');
  const [requestSearch, setRequestSearch] = useState('');
  const [donorRequestSearch, setDonorRequestSearch] = useState('');
  const [selectedRequestId, setSelectedRequestId] = useState('');
  const [requestMatches, setRequestMatches] = useState([]);
  const [users, setUsers] = useState([]);
  const [userPage, setUserPage] = useState(1);
  const [userPageSize] = useState(50);
  const [userTotal, setUserTotal] = useState(0);
  const [userSearch, setUserSearch] = useState('');
  const [userRoleFilter, setUserRoleFilter] = useState('ALL');
  const [notifications, setNotifications] = useState([]);

  const pageMeta = {
    'recipient-requests': {
      title: 'Recipient Requests',
      blurb: 'Review recipient-created requests and inspect match readiness.',
    },
    'donor-requests': {
      title: 'Donor Requests',
      blurb: 'Review donor-applied requests and approve or reject them.',
    },
    users: {
      title: 'User Governance',
      blurb: 'Verify users, enforce policy, and monitor identity compliance in one place.',
    },
    operations: {
      title: 'Operations Center',
      blurb: 'Track unread alerts and refresh platform signals quickly.',
    },
  };

  const activeMeta = pageMeta[view] || pageMeta['recipient-requests'];
  const showRecipientRequests = view === 'recipient-requests';
  const showDonorRequests = view === 'donor-requests';
  const showUsers = view === 'users';
  const showOperations = view === 'operations';

  useEffect(() => {
    refreshForView(view);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [view]);

  async function refreshForView(nextView) {
    setLoading(true);
    try {
      if (nextView === 'recipient-requests') {
        await loadRecipientRequests(true);
        return;
      }
      if (nextView === 'donor-requests') {
        await loadDonorRequests(true);
        return;
      }
      if (nextView === 'users') {
        await loadUsers(userPage, true);
        return;
      }
      await Promise.all([loadAnalytics(true), loadNotifications(true)]);
    } catch (error) {
      setFlash({ type: 'error', text: error.message });
    } finally {
      setLoading(false);
    }
  }

  async function loadAnalytics(silent = false) {
    const data = await apiRequest('/admin/analytics', { token });
    setAnalytics(data);
    if (!silent) setFlash({ type: 'success', text: 'Analytics refreshed.' });
  }

  async function loadRecipientRequests(silent = false) {
    const data = await apiRequest('/admin/requests?limit=250', { token });
    const sorted = [...(data.items || [])].sort(byCreatedDesc);
    setRequests(sorted);
    if (!selectedRequestId && sorted.length > 0) {
      setSelectedRequestId(sorted[0].request_id);
      await loadRequestMatches(sorted[0].request_id);
    }
    if (!silent) setFlash({ type: 'success', text: `Loaded ${sorted.length} recipient requests.` });
  }

  async function loadDonorRequests(silent = false) {
    const data = await apiRequest('/admin/donor-requests?limit=250', { token });
    const sorted = [...(data.items || [])].sort(byCreatedDesc);
    setDonorRequests(sorted);
    if (!silent) setFlash({ type: 'success', text: `Loaded ${sorted.length} donor requests.` });
  }

  async function loadUsers(page = userPage, silent = false) {
    const data = await apiRequest(`/admin/users?page=${page}&page_size=${userPageSize}`, { token });
    setUsers(data.items || []);
    setUserTotal(data.total || 0);
    setUserPage(page);
    if (!silent) setFlash({ type: 'success', text: `Loaded users page ${page}.` });
  }

  async function loadNotifications(silent = false) {
    const data = await apiRequest('/notifications/me?unread_only=true&limit=50', { token });
    setNotifications(data.items || []);
    if (!silent) setFlash({ type: 'success', text: `Loaded ${data.count || 0} unread notifications.` });
  }

  async function loadRequestMatches(requestId) {
    if (!requestId) return;
    const data = await apiRequest(`/matches/for-request/${requestId}`, { token });
    setRequestMatches(data.items || []);
    setSelectedRequestId(requestId);
  }

  async function acceptRequestByAdmin() {
    if (!selectedRequestId) return;
    const reason = window.prompt('Acceptance note', 'Request reviewed and approved for processing.');
    if (!reason) return;
    await apiRequest(`/admin/requests/${selectedRequestId}/accept`, {
      method: 'POST',
      token,
      body: { reason, details: reason },
    });
    setFlash({ type: 'success', text: 'Request accepted successfully.' });
    await loadRecipientRequests(true);
    await loadRequestMatches(selectedRequestId);
  }

  async function rejectRequestByAdmin() {
    if (!selectedRequestId) return;
    const reason = window.prompt('Rejection note', 'Request rejected by admin.');
    if (!reason) return;
    await apiRequest(`/admin/requests/${selectedRequestId}/block`, {
      method: 'POST',
      token,
      body: { reason, details: reason },
    });
    setFlash({ type: 'success', text: 'Request rejected successfully.' });
    await loadRecipientRequests(true);
    await loadRequestMatches(selectedRequestId);
  }

  async function deleteRequestByAdmin() {
    if (!selectedRequestId) return;
    const reason = window.prompt('Delete reason', 'Request removed by admin.');
    if (!reason) return;
    const confirmed = window.confirm('Delete this request permanently? This action cannot be undone.');
    if (!confirmed) return;
    await apiRequest(`/admin/requests/${selectedRequestId}?reason=${encodeURIComponent(reason)}`, {
      method: 'DELETE',
      token,
    });
    setFlash({ type: 'success', text: 'Request deleted successfully.' });
    setRequestMatches([]);
    setSelectedRequestId('');
    await loadRecipientRequests(true);
  }

  async function reviewDonorRequest(matchId, decision) {
    if (!matchId) return;
    const reason = window.prompt(
      decision === 'accept' ? 'Approval note' : 'Rejection note',
      decision === 'accept' ? 'Donor application approved by admin.' : 'Donor application rejected by admin.'
    );
    if (!reason) return;
    await apiRequest(`/admin/donor-requests/${matchId}/${decision}`, {
      method: 'POST',
      token,
      body: { reason, details: reason },
    });
    setFlash({ type: 'success', text: decision === 'accept' ? 'Donor request approved.' : 'Donor request rejected.' });
    await loadDonorRequests(true);
  }

  async function verifyUser(userId, verified) {
    const defaultText = verified ? 'ID verified and approved by admin.' : 'ID rejected due to mismatch in records.';
    const notes = window.prompt('Verification note', defaultText);
    if (!notes) return;
    await apiRequest(`/admin/verify-user/${userId}`, {
      method: 'POST',
      token,
      body: { verified, notes },
    });
    setFlash({ type: 'success', text: `Verification updated for user ${userId}.` });
    await loadUsers(userPage, true);
  }

  async function blockUser(userId) {
    const reason = window.prompt('Block reason', 'Policy violation detected during admin review.');
    if (!reason) return;
    const details = window.prompt('Additional details', reason) || reason;
    await apiRequest(`/admin/block-user/${userId}`, {
      method: 'POST',
      token,
      body: { reason, details },
    });
    setFlash({ type: 'success', text: `User ${userId} blocked.` });
    await loadUsers(userPage, true);
  }

  async function markNotificationRead(notificationId) {
    await apiRequest(`/notifications/${notificationId}/read`, {
      method: 'POST',
      token,
    });
    setNotifications((prev) => prev.filter((item) => item.notification_id !== notificationId));
  }

  const requestSummary = useMemo(() => {
    const summary = {
      ALL: requests.length,
      OPEN: 0,
      MATCHED: 0,
      IN_PROGRESS: 0,
      FULFILLED: 0,
      CANCELLED: 0,
      EXPIRED: 0,
    };

    requests.forEach((item) => {
      const key = item.status || 'OPEN';
      if (summary[key] !== undefined) summary[key] += 1;
    });

    return summary;
  }, [requests]);

  const filteredRequests = useMemo(() => {
    const needle = requestSearch.trim().toLowerCase();
    return requests.filter((item) => {
      if (requestStatus !== 'ALL' && item.status !== requestStatus) return false;
      if (!needle) return true;
      const haystack = [item.request_id, item.request_type, item.hospital_name, item.status, item.urgency_level]
        .filter(Boolean)
        .join(' ')
        .toLowerCase();
      return haystack.includes(needle);
    });
  }, [requests, requestSearch, requestStatus]);

  const filteredDonorRequests = useMemo(() => {
    const needle = donorRequestSearch.trim().toLowerCase();
    return donorRequests.filter((item) => {
      if (!needle) return true;
      const haystack = [
        item.match_id,
        item.request_id,
        item.request_type,
        item.donor_name,
        item.hospital_name,
        item.admin_review_status,
        item.donor_response,
      ]
        .filter(Boolean)
        .join(' ')
        .toLowerCase();
      return haystack.includes(needle);
    });
  }, [donorRequestSearch, donorRequests]);

  const filteredUsers = useMemo(() => {
    const needle = userSearch.trim().toLowerCase();
    return users.filter((item) => {
      if (userRoleFilter !== 'ALL' && item.role !== userRoleFilter) return false;
      if (!needle) return true;
      const haystack = [item.user_id, item.email, item.phone, item.role].filter(Boolean).join(' ').toLowerCase();
      return haystack.includes(needle);
    });
  }, [users, userRoleFilter, userSearch]);

  const selectedRequest = useMemo(
    () => requests.find((item) => item.request_id === selectedRequestId) || null,
    [requests, selectedRequestId]
  );

  const unreadCriticalCount = notifications.filter((item) => String(item.notification_type || '').toUpperCase().includes('CRITICAL')).length;

  return (
    <section className="panel full admin-page">
      <div className="admin-hero">
        <div>
          <p className="eyebrow">Admin Workspace</p>
          <h2>{activeMeta.title}</h2>
          <p className="muted-text">{activeMeta.blurb}</p>
        </div>
        <div className="admin-hero-chips">
          <span className="status-chip good">Total Requests: {requestSummary.ALL}</span>
          <span className="status-chip warn">Unread Alerts: {notifications.length}</span>
        </div>
      </div>

      {showRecipientRequests && (
        <div className="admin-grid">
          <article className="panel admin-section">
            <div className="admin-section-head">
              <h3>Recipient Request Feed</h3>
              <div className="tab-row">
                <button onClick={() => loadRecipientRequests(false)} disabled={loading}>Refresh Requests</button>
              </div>
            </div>

            <div className="admin-filter-grid">
              <select value={requestStatus} onChange={(e) => setRequestStatus(e.target.value)}>
                {requestStatusOptions.map((item) => <option key={item} value={item}>{item}</option>)}
              </select>
              <input
                placeholder="Search by request id, hospital, type, urgency"
                value={requestSearch}
                onChange={(e) => setRequestSearch(e.target.value)}
              />
            </div>

            <div className="table-shell">
              <table className="data-table admin-table">
                <thead>
                  <tr>
                    <th>Request ID</th>
                    <th>Type</th>
                    <th>Hospital</th>
                    <th>Urgency</th>
                    <th>Status</th>
                    <th>Created</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredRequests.map((item) => (
                    <tr
                      key={item.request_id}
                      className={selectedRequestId === item.request_id ? 'active-row' : ''}
                      onClick={() => loadRequestMatches(item.request_id)}
                      role="button"
                      tabIndex={0}
                    >
                      <td>{item.request_id}</td>
                      <td>{item.request_type}</td>
                      <td>{item.hospital_name || 'Unknown Hospital'}</td>
                      <td>{item.urgency_level}</td>
                      <td>{item.status}</td>
                      <td>{formatDate(item.created_at)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            {filteredRequests.length === 0 && <p className="muted-text">No requests match current filters.</p>}
          </article>

          <article className="panel admin-section">
            <div className="admin-section-head">
              <h3>Request Detail and Matches</h3>
              <div className="tab-row">
                <button onClick={() => loadRequestMatches(selectedRequestId)} disabled={!selectedRequestId}>Refresh Matches</button>
                <button onClick={acceptRequestByAdmin} disabled={!selectedRequestId}>Accept</button>
                <button onClick={rejectRequestByAdmin} disabled={!selectedRequestId}>Reject</button>
                <button className="danger" onClick={deleteRequestByAdmin} disabled={!selectedRequestId}>Delete</button>
              </div>
            </div>

            {!selectedRequest && <p className="muted-text">Select a request to inspect details and match readiness.</p>}

            {selectedRequest && (
              <>
                <div className="admin-detail-card">
                  <p><strong>Request ID:</strong> {selectedRequest.request_id}</p>
                  <p><strong>Type:</strong> {selectedRequest.request_type}</p>
                  <p><strong>Urgency:</strong> {selectedRequest.urgency_level}</p>
                  <p><strong>Status:</strong> {selectedRequest.status}</p>
                  <p><strong>Hospital:</strong> {selectedRequest.hospital_name || '-'}</p>
                  <p><strong>Created:</strong> {formatDate(selectedRequest.created_at)}</p>
                </div>

                <div className="table-shell">
                  <table className="data-table admin-table">
                    <thead>
                      <tr>
                        <th>Donor</th>
                        <th>Score</th>
                        <th>Distance</th>
                        <th>Status</th>
                        <th>Response</th>
                      </tr>
                    </thead>
                    <tbody>
                      {requestMatches.map((match) => (
                        <tr key={match.match_id}>
                          <td>{match.donor_name}</td>
                          <td>{Number(match.compatibility_score || 0).toFixed(2)}</td>
                          <td>{Number(match.distance_km || 0).toFixed(2)} km</td>
                          <td>{match.status}</td>
                          <td>{match.donor_response}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </>
            )}
          </article>
        </div>
      )}

      {showDonorRequests && (
        <article className="panel admin-section">
          <div className="admin-section-head">
            <h3>Donor Request Review</h3>
            <div className="tab-row">
              <button onClick={() => loadDonorRequests(false)} disabled={loading}>Refresh Donor Requests</button>
            </div>
          </div>

          <div className="admin-filter-grid">
            <input
              placeholder="Search donor, request id, hospital, status"
              value={donorRequestSearch}
              onChange={(e) => setDonorRequestSearch(e.target.value)}
            />
          </div>

          {filteredDonorRequests.length === 0 && <p className="muted-text">No donor requests match current filters.</p>}

          {filteredDonorRequests.length > 0 && (
            <div className="table-shell">
              <table className="data-table admin-table">
                <thead>
                  <tr>
                    <th>Request ID</th>
                    <th>Donor</th>
                    <th>Hospital</th>
                    <th>Type</th>
                    <th>Score</th>
                    <th>Admin Review</th>
                    <th>Action</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredDonorRequests.map((item) => (
                    <tr key={item.match_id}>
                      <td>{item.request_id}</td>
                      <td>{item.donor_name}</td>
                      <td>{item.hospital_name || '-'}</td>
                      <td>{item.request_type}</td>
                      <td>{Number(item.compatibility_score || 0).toFixed(2)}</td>
                      <td>{item.admin_review_status}</td>
                      <td>
                        <div className="tab-row">
                          <button
                            onClick={() => reviewDonorRequest(item.match_id, 'accept')}
                            disabled={String(item.admin_review_status).toUpperCase() !== 'PENDING'}
                          >
                            Accept
                          </button>
                          <button
                            className="danger"
                            onClick={() => reviewDonorRequest(item.match_id, 'reject')}
                            disabled={String(item.admin_review_status).toUpperCase() !== 'PENDING'}
                          >
                            Reject
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </article>
      )}

      {showUsers && (
        <article className="panel admin-section">
          <div className="admin-section-head">
            <h3>User Governance</h3>
            <div className="tab-row">
              <button onClick={() => loadUsers(userPage, false)} disabled={loading}>Refresh Users</button>
              <button onClick={() => loadUsers(Math.max(1, userPage - 1), false)} disabled={userPage <= 1}>Prev</button>
              <button onClick={() => loadUsers(userPage + 1, false)} disabled={(userPage * userPageSize) >= userTotal}>Next</button>
            </div>
          </div>

          <div className="admin-filter-grid">
            <select value={userRoleFilter} onChange={(e) => setUserRoleFilter(e.target.value)}>
              {roleOptions.map((item) => <option key={item} value={item}>{item}</option>)}
            </select>
            <input
              placeholder="Search by user id, email, phone"
              value={userSearch}
              onChange={(e) => setUserSearch(e.target.value)}
            />
          </div>

          <p className="muted-text">Showing {filteredUsers.length} of {users.length} users on page {userPage}. Total users: {userTotal}</p>

          <div className="table-shell">
            <table className="data-table admin-table">
              <thead>
                <tr>
                  <th>Email</th>
                  <th>User ID</th>
                  <th>Phone</th>
                  <th>Role</th>
                  <th>Verified</th>
                  <th>Blocked</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredUsers.map((user) => (
                  <tr key={user.user_id}>
                    <td>{user.email}</td>
                    <td>{user.user_id}</td>
                    <td>{user.phone}</td>
                    <td>{user.role}</td>
                    <td>{String(Boolean(user.id_verified))}</td>
                    <td>{String(Boolean(user.is_blocked))}</td>
                    <td>
                      <div className="tab-row">
                        <button onClick={() => verifyUser(user.user_id, true)}>Verify</button>
                        <button onClick={() => verifyUser(user.user_id, false)}>Reject</button>
                        <button className="danger" onClick={() => blockUser(user.user_id)}>Block</button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </article>
      )}

      {showOperations && (
        <article className="panel admin-section">
          <div className="admin-section-head">
            <h3>Operations and Alerts</h3>
            <div className="tab-row">
              <button onClick={() => loadNotifications(false)}>Refresh Alerts</button>
              <button onClick={() => loadAnalytics(false)}>Refresh Analytics</button>
            </div>
          </div>

          {analytics && (
            <div className="kpi-grid">
              <div className="kpi"><h3>Total Donors</h3><p>{analytics.metrics.total_donors}</p></div>
              <div className="kpi"><h3>Total Recipients</h3><p>{analytics.metrics.total_recipients}</p></div>
              <div className="kpi"><h3>Total Requests</h3><p>{analytics.metrics.total_requests}</p></div>
              <div className="kpi"><h3>Total Matches</h3><p>{analytics.metrics.total_matches}</p></div>
            </div>
          )}

          <div className="admin-mini-grid top-space">
            <div className="admin-mini-card"><strong>Unread Alerts</strong><span>{notifications.length}</span></div>
            <div className="admin-mini-card"><strong>Critical Alerts</strong><span>{unreadCriticalCount}</span></div>
            <div className="admin-mini-card"><strong>Open Requests</strong><span>{requestSummary.OPEN}</span></div>
            <div className="admin-mini-card"><strong>Matched Requests</strong><span>{requestSummary.MATCHED}</span></div>
          </div>

          <div className="table-shell top-space">
            <table className="data-table admin-table">
              <thead>
                <tr>
                  <th>Title</th>
                  <th>Type</th>
                  <th>Message</th>
                  <th>Created</th>
                  <th>Action</th>
                </tr>
              </thead>
              <tbody>
                {notifications.map((item) => (
                  <tr key={item.notification_id}>
                    <td>{item.title}</td>
                    <td>{item.notification_type}</td>
                    <td>{item.message}</td>
                    <td>{formatDate(item.created_at)}</td>
                    <td><button onClick={() => markNotificationRead(item.notification_id)}>Mark Read</button></td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </article>
      )}
    </section>
  );
}

export default AdminPage;
